"use client";

import { useState } from "react";
import Papa from "papaparse";
import EEGGraph from "../components/EEGGraph";
import { UploadCloud } from "lucide-react";
import { fft, util as fftUtil } from "fft-js";

type EEGData = {
    time: number;
    alpha: number;
    beta: number;
    gamma: number;
    };

    /* ===== FFT PROCESS ===== */
    function processEEG(signal: number[]): EEGData[] {
    const samplingRate = 128;
    const windowSize = 128;

    const result: EEGData[] = [];

    for (let i = 0; i < signal.length - windowSize; i += windowSize) {
        const segment = signal.slice(i, i + windowSize);

        const phasors = fft(segment);
        const magnitudes = fftUtil.fftMag(phasors);
        const freqs = fftUtil.fftFreq(phasors, samplingRate);

        let alpha = 0, beta = 0, gamma = 0;

        for (let j = 0; j < freqs.length; j++) {
        const f = freqs[j];
        const mag = magnitudes[j];

        if (f >= 8 && f <= 12) alpha += mag;
        else if (f > 12 && f <= 30) beta += mag;
        else if (f > 30) gamma += mag;
        }

        result.push({
        time: i,
        alpha: alpha / 10,
        beta: beta / 10,
        gamma: gamma / 10,
        });
    }

    return result;
    }

    /* ===== BRAIN STATE ===== */
    function classifyState(alpha: number, beta: number, gamma: number) {
    if (alpha > beta && alpha > gamma) return "Relaxed";
    if (beta > alpha && beta > gamma) return "Focused";
    if (gamma > beta) return "High Cognitive Load";
    return "Neutral";
    }

    export default function Home() {
    const [data, setData] = useState<EEGData[]>([]);
    const [state, setState] = useState("Idle");

    const handleFileUpload = (file: File) => {
        Papa.parse(file, {
        header: true,
        dynamicTyping: true,
        complete: (results: any) => {
            const values = results.data
            .map((row: any) => row.value)
            .filter((v: any) => typeof v === "number");

            const processed = processEEG(values);
            setData(processed);

            if (processed.length > 0) {
            const last = processed[processed.length - 1];
            setState(classifyState(last.alpha, last.beta, last.gamma));
            }
        },
        });
    };

    return (
        <div className="min-h-screen bg-[#0B0F14] text-white p-6">

        {/* HEADER */}
        <h1 className="text-2xl font-bold mb-6 text-cyan-400">
            🧠 Neuro Brain Scan
        </h1>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">

            {/* LEFT PANEL */}
            <div className="space-y-6">

            {/* Upload */}
            <div className="glass">
                <h2 className="text-sm text-gray-400 mb-3">Upload EEG</h2>

                <label className="upload-box">
                <UploadCloud size={28} className="mb-2 text-cyan-400" />
                <span className="text-sm">Upload CSV</span>

                <input
                    type="file"
                    accept=".csv"
                    className="hidden"
                    onChange={(e) =>
                    e.target.files && handleFileUpload(e.target.files[0])
                    }
                />
                </label>
            </div>

            {/* Brain State */}
            <div className="glass">
                <h2 className="text-sm text-gray-400 mb-3">Brain State</h2>
                <p className="text-xl font-semibold text-cyan-300">{state}</p>
            </div>

            {/* Stats */}
            <div className="glass">
                <h2 className="text-sm text-gray-400 mb-3">Signal Stats</h2>
                <p>Alpha: {avg(data, "alpha")}</p>
                <p>Beta: {avg(data, "beta")}</p>
                <p>Gamma: {avg(data, "gamma")}</p>
            </div>

            </div>

            {/* GRAPH */}
            <div className="col-span-3 glass p-6">
            <h2 className="text-lg mb-4 text-cyan-400">
                EEG Frequency Bands
            </h2>

            <EEGGraph data={data} />
            </div>

        </div>
        </div>
    );
    }

    /* ===== HELPER ===== */
    function avg(data: any[], key: string) {
    if (!data.length) return 0;
    return (
        data.reduce((sum, d) => sum + d[key], 0) / data.length
    ).toFixed(2);
}